INSERT INTO `posts` (`id`, `user_id`, `content`, `image_path`, `file_path`, `file_name`, `created_at`, `updated_at`) VALUES
(7, 1, 'Tabrakan KRL dan KA Argo Bromo Anggrek di Stasiun Bekasi Timur: 14 orang meninggal, proses evakuasi diakhiri. Adapun 84 korban luka-luka tengah dirawat di sejumlah fasilitas kesehatan. #beritaterkini #fyp', 'posts/images/PIB6clEF6mldF10wJiCjMZuuCCTnhzejMTZgwilU.webp', NULL, NULL, '2026-04-27 22:03:49', '2026-04-27 22:22:23'),
(8, 2, '\"Trump Tak Senang dengan Proposal Baru Iran Soal Selat Hormuz\".\r\n#beritainternasional\r\n#beritaterkini\r\n#fyp', 'posts/images/TtRj5fnuu9mDdOLEPJlM58r5SeCTX4VMsdlzWr5H.jpg', NULL, NULL, '2026-04-27 22:51:08', '2026-04-27 22:52:45'),
(9, 1, 'halo #fyp', NULL, NULL, NULL, '2026-04-28 08:27:21', '2026-04-28 08:27:21'),
(10, 2, 'Iran dilaporkan telah mengusulkan proposal perundingan damai baru menyusul upaya Pakistan sebagai mediator untuk mencari jalan tengah agar putaran dua perundingan mengakhiri perang dengan Amerika Serikat bisa dilanjutkan.\r\n#fyp\r\n#beritainternasional', 'posts/images/0CdZcLpi61jRZ0TzEMJJMCnNTWddC4EMR1xIYdaK.jpg', NULL, NULL, '2026-04-28 18:06:47', '2026-04-28 18:06:47'),
(11, 1, 'Cerita pilu datang dari Endang Kuswati (40), korban kecelakaan kereta api Argo Bromo Anggrek dengan KRL di Stasiun Bekasi Timur. Dia harus menunggu bantuan selama 10 jam usai terjepit di dalam gerbong KRL yang ditabrak KA Argo Bromo.\r\n#beritaterkini', 'posts/images/cYP7FhF1ho4AUuUz2KavPYrt40yyWXQ3Pcfa95TZ.jpg', NULL, NULL, '2026-04-28 18:50:10', '2026-04-28 20:47:27'),
(13, 1, 'bdshbhsbhsdbhb\r\n#beritainternasional1', 'posts/images/eXeagPEL8NRlerhzVHBaqrzZwqLyK0pdJjx5UnHG.jpg', NULL, NULL, '2026-04-28 23:39:55', '2026-04-28 23:43:41');
