te\\\\Database\\\\Eloquent\\\\Collection\",\"properties\":[{\"id\":11,\"user_id\":1,\"content\":\"Cerita pilu datang dari Endang Kuswati (40), korban kecelakaan kereta api Argo Bromo Anggrek dengan KRL di Stasiun Bekasi Timur. Dia harus menunggu bantuan selama 10 jam usai terjepit di dalam gerbong KRL yang ditabrak KA Argo Bromo.\\r\\n#beritaterkini\",\"image_path\":\"posts\\/images\\/fklkcoCszEm061oQFheAMd5tc6rb6SVa7WuKbq3y.jpg\",\"file_path\":null,\"file_name\":null,\"created_at\":\"2026-04-29T01:50:10.000000Z\",\"updated_at\":\"2026-04-29T01:50:10.000000Z\",\"user\":{\"id\":1,\"name\":\"rayhan\",\"username\":\"veyrha\",\"email\":\"8rayhanrahadhan@gmail.com\",\"email_verified_at\":null,\"bio\":\"stecu\",\"profile_photo_path\":\"profiles\\/Zf0rkc1TmRmBgCxdkKnzqY1PKfet7NjqxlOP05Op.jpg\",\"created_at\":\"2026-04-27T15:12:19.000000Z\",\"updated_at\":\"2026-04-28T16:31:51.000000Z\"},\"comments\":[{\"id\":23,\"post_id\":11,\"user_id\":1,\"content\":\"tolong sebarkan ya #fyp\",\"image_path\":null,\"file_path\":null,\"file_name\":null,\"created_at\":\"2026-04-29T01:52:41.000000Z\",\"updated_at\":\"2026-04-29T02:48:53.000000Z\",\"parent_id\":null},{\"id\":24,\"post_id\":11,\"user_id\":1,\"content\":\"pliss banget\",\"image_path\":null,\"file_path\":null,\"file_name\":null,\"created_at\":\"2026-04-29T01:53:56.000000Z\",\"updated_at\":\"2026-04-29T01:53:56.000000Z\",\"parent_id\":23}],\"likes\":[{\"id\":11,\"post_id\":11,\"user_id\":1,\"created_at\":\"2026-04-29T01:52:20.000000Z\",\"updated_at\":\"2026-04-29T01:52:20.000000Z\"}]},{\"id\":10,\"user_id\":2,\"content\":\"Iran dilaporkan telah mengusulkan proposal perundingan damai baru menyusul upaya Pakistan sebagai mediator untuk mencari jalan tengah agar putaran dua perundingan mengakhiri perang dengan Amerika Serikat bisa dilanjutkan.\\r\\n#fyp\\r\\n#beritainternasional\",\"image_path\":\"posts\\/images\\/0CdZcLpi61jRZ0TzEMJJMCnNTWddC4EMR1xIYdaK.jpg\",\"file_path\":null,\"file_name\":null,\"created_at\":\"2026-04-29T01:06:4